          "relative w-fit",
          "[transform-style:preserve-3d]",
          "[container-type:inline-size]",
          !shouldReduceMotion && [
            "transition-transform duration-[250ms] ease-out",
            "hover:[transform:rotateY(-20deg)_scale(1.066)_translateX(-8px)]",
          ]
        )}
        style={{
          aspectRatio: "49 / 60",
